package ir.tahamohamadi.publication.api.admin;
import ir.tahamohamadi.common.api.PageResponse; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.http.*; import org.springframework.validation.annotation.Validated; import org.springframework.web.bind.annotation.*; import java.util.UUID;
@RestController @Validated @RequestMapping("/api/v1/admin/publications") public class AdminPublicationController { private final AdminPublicationService service; public AdminPublicationController(AdminPublicationService service){this.service=service;} @GetMapping public PageResponse<AdminPublicationSummary> list(@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(100) int size,@RequestParam(defaultValue="updatedAt,desc") String sort){return PageResponse.from(service.list(page,size,sort));} @GetMapping("/{id}") public AdminPublicationResponse get(@PathVariable UUID id){return service.get(id);} @PostMapping public ResponseEntity<AdminPublicationResponse> create(@Valid @RequestBody AdminPublicationRequest request){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(request));} @PutMapping("/{id}") public AdminPublicationResponse update(@PathVariable UUID id,@Valid @RequestBody AdminPublicationRequest request){return service.update(id,request);} @PostMapping("/{id}/publish") public AdminPublicationResponse publish(@PathVariable UUID id,@RequestParam @Min(0) long version){return service.publish(id,version);} @PostMapping("/{id}/archive") public AdminPublicationResponse archive(@PathVariable UUID id,@RequestParam @Min(0) long version){return service.archive(id,version);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id,@RequestParam @Min(0) long version){service.delete(id,version);} }
